        if not self.is_empty():
            return self.items.popleft()
        return None

    def pop_back(self):
        if not self.is_empty():
            return self.items.pop()
        return None

    def front(self):
        if not self.is_empty():
            return self.items[0]
        return None

    def back(self):
        if not self.is_empty():
            return self.items[-1]
        return None

    def is_empty(self):
        return len(self.items) == 0

    def to_list(self):
        return list(self.items)

