#include <stdio.h>
#include <stdlib.h>
#define MAX_SIZE 100

typedef struct Deque {
    int items[MAX_SIZE];
    int front_idx;
    int rear;
} Deque;

void initDeque(Deque* deq) {
    deq->front_idx = MAX_SIZE / 2;
    deq->rear = MAX_SIZE / 2 - 1;
}

void push_front(Deque* deq, int item) {
    if (deq->front_idx > 0) {
        deq->items[--deq->front_idx] = item;
    }
}

void push_back(Deque* deq, int item) {
    if (deq->rear < MAX_SIZE - 1) {
        deq->items[++deq->rear] = item;
    }
}

int pop_front(Deque* deq) {
    if (!isEmpty(deq)) {
        return deq->items[deq->front_idx++];
    }
    return -1;
}

int pop_back(Deque* deq) {
    if (!isEmpty(deq)) {
        return deq->items[deq->rear--];
    }
    return -1;
}

int front(Deque* deq) {
    if (!isEmpty(deq)) {
        return deq->items[deq->front_idx];
    }
    return -1;
}

int back(Deque* deq) {
    if (!isEmpty(deq)) {
        return deq->items[deq->rear];
    }
    return -1;
}

int isEmpty(Deque* deq) {
    return deq->front_idx > deq->rear;
}

void printDeque(Deque* deq) {
    printf("[");
    for (int i = deq->front_idx; i <= deq->rear; i++) {
        printf("%d", deq->items[i]);
        if (i < deq->rear) printf(", ");
    }
    printf("]\n");
}

int main() {
    Deque deq;
    initDeque(&deq);
    push_front(&deq, 10);
    push_front(&deq, 5);
    push_back(&deq, 15);
    printf("Deque after push: ");
    printDeque(&deq);
    int frontPopped = pop_front(&deq);
    int backPopped = pop_back(&deq);
    printf("Popped front: %d\n", frontPopped);
    printf("Popped back: %d\n", backPopped);
    printf("Deque after pop: ");
    printDeque(&deq);
    printf("Front item: %d\n", front(&deq));
    printf("Back item: %d\n", back(&deq));
    return 0;
}
// Output: Deque after push: [5, 10, 15]
// Output: Popped front: 5
// Output: Popped back: 15
// Output: Deque after pop: [10]
// Output: Front item: 10
// Output: Back item: 10

