#include <iostream>
#include <vector>

class Deque {
private:
    std::vector<int> items;

public:
    void push_front(int item) {
        items.insert(items.begin(), item);
    }

    void push_back(int item) {
        items.push_back(item);
    }

    int pop_front() {
        if (!isEmpty()) {
            int item = items.front();
            items.erase(items.begin());
            return item;
        }
        return -1;
    }

    int pop_back() {
        if (!isEmpty()) {
            int item = items.back();
            items.pop_back();
            return item;
        }
        return -1;
    }

    int front() {
        if (!isEmpty()) {
            return items.front();
        }
        return -1;
    }

    int back() {
        if (!isEmpty()) {
            return items.back();
        }
        return -1;
    }

    bool isEmpty() {
        return items.empty();
    }

    std::vector<int> toVector() {
        return items;
    }
};

int main() {
    Deque deq;
    deq.push_front(10);
    deq.push_front(5);
    deq.push_back(15);
    std::cout << "Deque after push: [";
    auto result = deq.toVector();
    for (size_t i = 0; i < result.size(); i++) {
        std::cout << result[i];
        if (i < result.size() - 1) std::cout << ", ";
